export function resolveSkuDisplayName({
  skuPartNumber,
  skuId,
}: {
  skuPartNumber?: string;
  skuId?: string;
}): string | undefined {
  if (skuPartNumber && skuDisplayNameByPartNumber[skuPartNumber]) {
    return skuDisplayNameByPartNumber[skuPartNumber].displayName;
  }

  if (skuId && skuDisplayNameBySkuId[skuId]) {
    return skuDisplayNameBySkuId[skuId].displayName;
  }

  return undefined;
}
